e failures\n        raise RuntimeError(f\"Failed to unpickle reconstructed state: {e}\") from e\n\n    return obj\n\n\ndef main():\n    obj = reconstruct_state()\n    # Minimal representation to stdout so operator can inspect or redirect\n    print(\"[state_reconstructor] Reconstructed object type:\", type(obj))\n    print(\"[state_reconstructor] Object repr (truncated):\")\n    try:\n        repr_str = repr(obj)\n    except Exception:\n        repr_str = \"<unrepresentable object>\"\n\n    # Avoid flooding the console in case of huge configs\n    if len(repr_str) > 2000:\n        repr_str = repr_str[:2000] + \"... [truncated]\"\n\n    print(repr_str)\n\n\nif __name__ == \"__main__\":\n    main()\n```\n\n使用方式（在目标主机上）：\n\n```bash\ncd /tmp/disaster_recovery\npython -m state_reconstructor\n```\n\n这会从 `crash_segment.bin` 中恢复对象，并在 stdout 打印类型和（截断后的）配置内容，便于你将配置迁移到备用节点。",
